"""
MVP installer v2 -- 7-day approval workflow.
Run from ~/workspace:  python install_mvp.py

What this installs:
  pacing/orchestrator.py    -- approval-gated daily dispatch
  pacing/weekly_brief.py    -- Sunday 9pm 7-day lookahead to Slack
  workers/seo_blog.py       -- Tier 1 auto blog publisher
  scripts/cron_dispatch.py  -- updated schedule
  db/migrations/005+006     -- calendar_executions + calendar_approvals tables
  APPROVE_ENDPOINT_README.py -- add this route to your FastAPI app
"""
import base64, os

def write(path, b64):
    os.makedirs(os.path.dirname(path) if os.path.dirname(path) else ".", exist_ok=True)
    open(path,"wb").write(base64.b64decode(b64))
    print("  wrote " + path)

FILES = {
    'pacing/orchestrator.py': '',
    'pacing/weekly_brief.py': '',
    'workers/seo_blog.py': '',
    'scripts/cron_dispatch.py': '',
    'db/migrations/005_calendar_executions.sql': '',
    'db/migrations/006_calendar_approvals.sql': '',
    'APPROVE_ENDPOINT_README.py': '',
}

print("Writing files...")
for path, b64 in FILES.items():
    write(path, b64)

print("\nRunning DB migrations...")
try:
    import psycopg
    url = os.environ.get("DATABASE_URL")
    with psycopg.connect(url) as conn:
        for n in ["005","006"]:
            sql = open("db/migrations/" + n + "_calendar_" + ("executions" if n=="005" else "approvals") + ".sql").read()
            conn.execute(sql)
        conn.commit()
    print("  migrations applied")
except Exception as e:
    print("  migration note: " + str(e))

print("""
Done.

IMPORTANT: Add the approval endpoint to your FastAPI app.
  1. Open APPROVE_ENDPOINT_README.py
  2. Copy the router and add to your main FastAPI app:
     from APPROVE_ENDPOINT_README import router as approve_router
     app.include_router(approve_router)

Also set REPLIT_DOMAIN in your Replit Secrets to your app domain.

Test the weekly brief now:
  python -c "from pacing.weekly_brief import run_weekly_brief; run_weekly_brief()"

After approving in Slack, test the orchestrator:
  python -c "from pacing.orchestrator import run_daily; run_daily()"
""")
